def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t in O(|s|·|t|) time
    and O(|t|) extra space."""
    n, m = len(s), len(t)
    if m == 0:
        return 1
    if n == 0:
        return 0

    # dp[j] = number of ways to form t[:j] using processed characters of s
    dp = [0] * (m + 1)
    dp[0] = 1  # empty t can always be formed

    for i in range(n):
        # iterate j backwards so we reuse the previous row's values
        for j in range(m, 0, -1):
            if s[i] == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
